package geometries.impl;

import primitives.Point;
import primitives.Ray;
import primitives.Vector;

/**
 * Cylinder represents a finite cylindrical tube with a given height.
 */
public class Cylinder extends Tube {
    private final double _height;

    /**
     * Constructs a cylinder with the specified radius, axis ray, and height.
     * @param radius the radius of the cylinder
     * @param axis   the central axis ray of the cylinder
     * @param height the height of the cylinder
     */
    public Cylinder(double radius, Ray axis, double height) {
        super(radius, axis);
        _height = height;
    }

    @Override
    public Vector getNormal(Point point) {
        // Normal computation is not required for this stage; can be implemented later.
        return null;
    }
}

package geometries.impl;

import geometries.api.Geometry;
import primitives.Point;
import primitives.Vector;

/**
 * Plane class represents an infinite plane in 3D space.
 * A plane is defined by a point on the plane and a normal vector.
 */
public class Plane extends Geometry {
    private final Point _point;
    private final Vector _normal;

    /**
     * Constructs a plane from three points.
     * @param p1 first point on the plane
     * @param p2 second point on the plane
     * @param p3 third point on the plane
     * @throws IllegalArgumentException if the three points are collinear
     */
    public Plane(Point p1, Point p2, Point p3) {
        // Create two vectors from the three points
        Vector v1 = new Vector(p2._xyz.subtract(p1._xyz));
        Vector v2 = new Vector(p3._xyz.subtract(p1._xyz));

        // Calculate the normal vector using cross product
        Vector normal = v1.crossProduct(v2);

        this._point = p1;
        this._normal = normal;
    }

    /**
     * Constructs a plane from a point and a normal vector.
     * @param point a point on the plane
     * @param normal the normal vector to the plane
     */
    public Plane(Point point, Vector normal) {
        this._point = point;
        this._normal = normal;
    }

    /**
     * Gets a point on the plane.
     * @return a point on the plane
     */
    public Point getPoint() {
        return _point;
    }

    /**
     * Gets the normal vector to the plane.
     * @return the normal vector to the plane
     */
    public Vector getNormal() {
        return _normal;
    }

    @Override
    public Vector getNormal(Point point) {
        return _normal;
    }
}

package geometries.impl;

import geometries.api.Geometry;
import primitives.Point;
import primitives.Vector;

/**
 * Plane class represents an infinite plane in 3D space.
 * A plane is defined by a point on the plane and a normalized normal vector.
 */
public class Plane extends Geometry {
    private final Point _q0;
    private final Vector _normal;

    /**
     * Constructs a plane from three non-collinear points.
     * @param p1 first point on the plane
     * @param p2 second point on the plane
     * @param p3 third point on the plane
     * @throws IllegalArgumentException if the three points are collinear
     */
    public Plane(Point p1, Point p2, Point p3) {
        Vector v1 = p2.subtract(p1);
        Vector v2 = p3.subtract(p1);
        _normal = v1.crossProduct(v2).normalize();
        _q0 = p1;
    }

    /**
     * Constructs a plane from a point and a normal vector.
     * The normal is normalized by the constructor.
     * @param point  a point on the plane
     * @param normal the normal vector to the plane
     */
    public Plane(Point point, Vector normal) {
        _q0 = point;
        _normal = normal.normalize();
    }

    @Override
    public Vector getNormal(Point point) {
        return _normal;
    }
}

package geometries.impl;

import geometries.api.Geometry;

abstract class RadialGeometry extends Geometry {
    protected double _radius;
    protected double _radiusSquared;

    /**
     * Constructs a radial geometry with the specified radius.
     * @param  radius the radius of the geometry
     * @throws IllegalArgumentException if the radius is not positive
     */
    public RadialGeometry(double radius) {
        if (radius <= 0)
            throw new IllegalArgumentException("Radius must be positive");
        _radius = radius;
    }

    public double getRadius() { return _radius; }

    public double get_radiusSquared() {
        return _radiusSquared;
    }
}

package geometries.impl;

import geometries.api.Geometry;

/**
 * Abstract base class for geometries defined by a radius.
 */
abstract class RadialGeometry extends Geometry {
    protected final double _radius;
    protected final double _radiusSquared;

    /**
     * Constructs a radial geometry with the specified radius.
     * @param radius the radius of the geometry
     * @throws IllegalArgumentException if the radius is not positive
     */
    public RadialGeometry(double radius) {
        if (radius <= 0)
            throw new IllegalArgumentException("Radius must be positive");
        _radius = radius;
        _radiusSquared = radius * radius;
    }

    public double getRadius() { return _radius; }

    public double get_radiusSquared() {
        return _radiusSquared;
    }
}

